use std::sync::atomic::AtomicI64; use crate::eval::sexp::Sexp;
static MAKE_SYMBOL_COUNTER: AtomicI64 = AtomicI64::new(0); #[no_mangle] pub extern "C" fn nl_make_symbol_counter_ptr() -> *mut i64 { std::ptr::addr_of!(MAKE_SYMBOL_COUNTER) as *mut i64 }
#[no_mangle] pub unsafe extern "C" fn nl_jit_format_float(x: f64, conv: u32, prec: i64, out: *mut Sexp) -> i64 { let (Some(ch), false) = (char::from_u32(conv), prec < 0) else { return 1 }; let p = prec as usize; let body = match ch { 'f'|'F' => format!("{:.*}",p,x), 'e' => format!("{:.*e}",p,x), 'E' => format!("{:.*E}",p,x), 'g'|'G' => { let (f,e)=(format!("{:.*}",p,x),format!("{:.*e}",p,x)); if f.len()<=e.len(){f}else{e} } _ => return 1 }; *out = Sexp::Str(body); 0 }
crate::define_nlbox!(inner=NlStr, ref_ty=NlStrRef, fields={value: String}, clone_fn=crate::elisp_cc_spike::nlstr_clone, drop_fn=crate::elisp_cc_spike::nlstr_drop, layout_asserts={ assert!(offset_of!(NlStr, value) == 0); assert!(offset_of!(NlStr, refcount) == size_of::<String>()); });
impl NlStrRef { pub unsafe fn set_value(&self, val: String) { let p = std::ptr::addr_of_mut!((*self.ptr.as_ptr()).value); std::ptr::drop_in_place(p); std::ptr::write(p, val); } } impl std::fmt::Debug for NlStrRef { fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result { f.debug_tuple("MutStr").field(&self.value).finish() } }
impl PartialEq for NlStrRef { fn eq(&self, other: &Self) -> bool { Self::ptr_eq(self, other) || self.value == other.value } }
macro_rules! mut_str_val_mut { ($p:expr) => { &mut (*((*$p).mut_str_box_ptr() as *mut NlStr)).value }; } #[no_mangle] pub extern "C" fn nl_is_char_alphanumeric(cp: i64) -> i64 { char::from_u32(cp as u32).map_or(0, |c| c.is_alphanumeric() as i64) } #[no_mangle] pub unsafe extern "C" fn nl_mut_str_set_codepoint_raw(arg: *const Sexp, idx: i64, val_cp: i64, out: *mut Sexp) -> i64 { use crate::jit::{TRAMPOLINE_ERR, TRAMPOLINE_OK}; let rc = match &*arg { Sexp::MutStr(r) => r, _ => return TRAMPOLINE_ERR }; let new_ch = match char::from_u32(val_cp as u32) { Some(c) => c, None => return TRAMPOLINE_ERR }; let i = idx as usize; if i >= rc.value.chars().count() { return TRAMPOLINE_ERR; } rc.set_value(rc.value.chars().enumerate().map(|(j, c)| if j == i { new_ch } else { c }).collect()); *out = Sexp::Int(val_cp); TRAMPOLINE_OK }
#[no_mangle] pub unsafe extern "C" fn nl_mut_str_push_byte(mut_str_ptr: *mut Sexp, byte: i64) { mut_str_val_mut!(mut_str_ptr).as_mut_vec().push((byte & 0xFF) as u8); } #[no_mangle] pub unsafe extern "C" fn nl_mut_str_push_codepoint(mut_str_ptr: *mut Sexp, codepoint: i64) { let cp = if !(0..=0x10_FFFF).contains(&codepoint) { 0xFFFD } else { codepoint as u32 }; mut_str_val_mut!(mut_str_ptr).push(char::from_u32(cp).unwrap_or('\u{FFFD}')); } #[no_mangle] pub unsafe extern "C" fn nl_sexp_write_float(slot: *mut Sexp, val: f64) -> *mut Sexp { std::ptr::write(slot, Sexp::Float(val)); slot } #[no_mangle] pub unsafe extern "C" fn nl_str_to_float(bytes_ptr: *const u8, len: i64, slot: *mut Sexp) -> i64 { let n = len.max(0) as usize; let s = if n == 0 { &[] } else { std::slice::from_raw_parts(bytes_ptr, n) }; match std::str::from_utf8_unchecked(s).parse::<f64>() { Ok(f) => { std::ptr::write(slot, Sexp::Float(f)); 1 } Err(_) => { std::ptr::write(slot, Sexp::Nil); 0 } } }
#[no_mangle] pub unsafe extern "C" fn nl_i64_append_to_mut_str(n: i64, buf: *mut Sexp) -> i64 { if matches!(&*buf, Sexp::MutStr(_)) { mut_str_val_mut!(buf).push_str(&n.to_string()); 0 } else { 1 } } #[no_mangle] pub unsafe extern "C" fn nl_f64_bits_append_to_mut_str(bits: i64, buf: *mut Sexp) -> i64 { if !matches!(&*buf, Sexp::MutStr(_)) { return 1; } let s = format!("{}", f64::from_bits(bits as u64)); let val = mut_str_val_mut!(buf); val.push_str(&s); if !s.contains(['.','e','E']) && s!="inf" && s!="-inf" && s!="NaN" { val.push_str(".0"); } 0 }
